import{_ as e,c as i,o as l,ae as o}from"./chunks/framework.D4x4JNJ3.js";const m=JSON.parse('{"title":"版本更新日志 v2025.1.x","description":"","frontmatter":{"title":"版本更新日志 v2025.1.x"},"headers":[],"relativePath":"zh/changelog/v2025.1.x.md","filePath":"zh/changelog/v2025.1.x.md","lastUpdated":1772097359000}'),t={name:"zh/changelog/v2025.1.x.md"};function r(n,a,c,s,d,h){return l(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="mogan-stem-v2025-1-x-版本更新日志" tabindex="-1">Mogan STEM v2025.1.x 版本更新日志 <a class="header-anchor" href="#mogan-stem-v2025-1-x-版本更新日志" aria-label="Permalink to “Mogan STEM v2025.1.x 版本更新日志”">​</a></h1><blockquote><p>说明：Liii STEM 是 Mogan STEM 的商业版，会在开源版的基础上提供账号登录、AI 等增值能力更多细节见Liii STEM：<a href="https://liiistem.cn/docs/changelog-v2025.1.x.html" target="_blank" rel="">v2025.1.x</a>。</p></blockquote><h2 id="⭐️-全新功能和亮点" tabindex="-1">⭐️ 全新功能和亮点 <a class="header-anchor" href="#⭐️-全新功能和亮点" aria-label="Permalink to “⭐️ 全新功能和亮点”">​</a></h2><ol><li><strong>现代化 UI 与主题</strong>：新增 Liii / Liii Dark 主题与全套矢量化图标，界面更统一。</li><li><strong>底层升级</strong>：升级到 TeXmacs 2.1.4，并内嵌自研编程语言 <strong>goldfish scheme</strong>。</li><li><strong>Tab Cycling / 智能补全</strong>：文本、数学与宏命令补全；积分/求和/集合符号与数学字体（<code>\\mathcal</code>/<code>\\mathbf</code>/<code>\\mathfrak</code> 等）支持 Tab 循环输入。</li><li><strong>多标签页体验升级</strong>：新增/切换标签页快捷键（macOS <code>Cmd+T</code>、<code>Cmd+1-6</code>），并提升多标签页管理与稳定性。</li><li><strong>导出与文件处理增强</strong>：PDF 导出增加进度与完成提示；按文件头识别图片格式减少导出失败；保存/另存为/打开对话框的可选文件格式展示完善。</li><li><strong>稳定性与性能优化</strong>：启动、编辑、渲染性能优化；修复 <code>&lt;</code>/<code>&gt;</code> 叠影、中文省略号卡死、复制崩溃、调试窗口无法打开等问题。</li></ol><h2 id="🌟-总结" tabindex="-1">🌟 总结 <a class="header-anchor" href="#🌟-总结" aria-label="Permalink to “🌟 总结”">​</a></h2><p>v2025.1.x 系列围绕“更现代的界面、更快的输入、更可靠的编辑体验”持续迭代：主题与图标整体升级，Tab Cycling 覆盖文本/数学/宏与常用符号输入，多标签页与导出体验加强，并持续打磨稳定性与性能。</p><h2 id="🔧-更新日志" tabindex="-1">🔧 更新日志 <a class="header-anchor" href="#🔧-更新日志" aria-label="Permalink to “🔧 更新日志”">​</a></h2><h3 id="mogan-stem-v2025-1-4-2025-10-06" tabindex="-1">Mogan STEM v2025.1.4 (2025/10/06) <a class="header-anchor" href="#mogan-stem-v2025-1-4-2025-10-06" aria-label="Permalink to “Mogan STEM v2025.1.4 (2025/10/06)”">​</a></h3><ol><li>输入增强：积分/求和/累乘/集合符号 Tab 循环输入；数学字体 Tab Cycling 优化；新增 <code>\\mathscr</code> 宏支持。</li><li>导出与图片：PDF 导出增加进度提示并在完成后询问是否打开；图片格式按文件头自动识别，避免后缀与内容不一致导致导出失败。</li><li>Emoji：支持通过 <code>:smile:</code> 等方式快速插入 Emoji。</li><li>体验与兼容：非 macOS 平台 Meta 键显示为 Win/Super；保存/另存为/打开对话框的格式选项完善；macOS 兼容性修复。</li><li>修复：中文省略号插入卡死、<code>&lt;</code>/<code>&gt;</code> 叠影、verbatim 不能换行、复制大段文本崩溃、调试窗口打不开等。</li></ol><p>更多细节见Liii STEM：<a href="https://liiistem.cn/docs/changelog-v2025.1.x.html" target="_blank" rel="">v2025.1.x</a></p><h3 id="mogan-stem-v2025-1-1-2025-08-21" tabindex="-1">Mogan STEM v2025.1.1 (2025/08/21) <a class="header-anchor" href="#mogan-stem-v2025-1-1-2025-08-21" aria-label="Permalink to “Mogan STEM v2025.1.1 (2025/08/21)”">​</a></h3><ol><li>项目更名：Mogan 更名为 <strong>Mogan STEM</strong>，并发布 v2025.1.1。</li><li>底层升级：升级到 TeXmacs 2.1.4，并内嵌自研编程语言 <strong>goldfish scheme</strong>。</li><li>主题与图标：新增 Liii / Liii Dark 主题；大量图标升级为矢量并统一风格；工具栏补充高亮等入口（部分 AI 入口为商业版 Liii STEM 独有）。</li><li>Tab 补全：数学字符 Tab Cycling；label/单词补全；宏命令补全。</li><li>多标签页：macOS <code>Cmd+T</code> 新建标签页、<code>Cmd+1-6</code> 切换；新增窗口附着/脱离管理并修复多标签页相关问题。</li><li>排版与编辑：语义块采用欧式编号风格并新增 Assumption 环境；乘号默认显示 <code>×</code> 且可用 Tab 切换；新增多重积分相关 LaTeX 宏；结构化搜索替换窗口嵌入为辅助窗口；魔法粘贴与 Emoji（内测）支持增强。</li><li>性能：启动、编辑与渲染更流畅。</li></ol><p>更多细节见Liii STEM：<a href="https://liiistem.cn/docs/changelog-v2025.1.x.html" target="_blank" rel="">v2025.1.x</a></p><h2 id="👏-加入社区" tabindex="-1">👏 加入社区 <a class="header-anchor" href="#👏-加入社区" aria-label="Permalink to “👏 加入社区”">​</a></h2><ul><li>墨干社区 QQ 群：934456971</li><li>Discord 群组：<a href="https://discord.gg/Q7xARnAf8t" target="_blank" rel="">https://discord.gg/Q7xARnAf8t</a></li><li>官网：<a href="https://mogan.app/" target="_blank" rel="">https://mogan.app/</a></li></ul>',15)])])}const p=e(t,[["render",r]]);export{m as __pageData,p as default};
